// Stale-goal cleanup (D1). Without it, once 3 stale auto-generated goals pile up
// the `<3 active` generation gate clogs permanently and auto-gen dies. A goal is
// stale when it is active, has made ZERO progress, and hasn't changed for ≥3 days.
// We DELETE it (never drive progress to target — that would falsely read as
// "achieved").
//
// SAFETY-CRITICAL ATTRIBUTION: the backend returns no `source` field (verified —
// GoalResponse omits it), so a self-generated goal can only be recognised from
// the local record this app keeps (appSettings.goalAutoGeneratedIds). Cleanup
// therefore considers ONLY goals in that set. A user-created goal is never in the
// set, so it can never be deleted here — the invariant a false positive would
// violate. Pruning is limited to ids we actually deleted, so a transient
// list-goals failure ([] on error) can never wipe the attribution record and
// orphan real auto-goals.
import { net } from 'electron'
import { getAbortSignal, getBackendSession, type BackendSession } from '../core/session'
import { getAppSettings, setAppSettings, type GoalAutoGeneratedRecord } from '../../appSettings'

/** A goal is stale after 3 days of zero-progress inactivity (Mac's threshold). */
const STALE_THRESHOLD_MS = 3 * 24 * 60 * 60 * 1000
const REQUEST_TIMEOUT_MS = 15_000

/** The fields cleanup needs from an active goal. */
export type StaleGoal = {
  id: string
  currentValue: number
  /** Epoch ms of the goal's last change (updated_at), or null when unknown. */
  updatedAt: number | null
}

/** Injected side-effects, so the decision is unit-testable without network. */
export type StaleCleanupDeps = {
  /** Active goals (/v1/goals/all). Fails open to [] — a transient failure then
   *  deletes nothing and prunes nothing (safe). */
  listGoals: () => Promise<StaleGoal[]>
  /** DELETE /v1/goals/{id}. Rejecting keeps the id in the record to retry later. */
  deleteGoal: (id: string) => Promise<void>
  getAttribution: () => GoalAutoGeneratedRecord[]
  setAttribution: (records: GoalAutoGeneratedRecord[]) => void
  now: number
}

/** Ids of the goals deleted this run. */
export type StaleCleanupResult = { deleted: string[] }

/**
 * Delete stale auto-generated goals with injected side-effects. Only goals in the
 * attribution set are ever considered; of those, one is deleted iff it is present
 * in the active list AND has zero progress AND is ≥3 days old (by updated_at, or
 * the record's createdAt when the backend gave no timestamp). Never throws — a
 * per-goal delete failure is swallowed and its id kept for the next run.
 */
export async function removeStaleGoalsWith(deps: StaleCleanupDeps): Promise<StaleCleanupResult> {
  const records = deps.getAttribution()
  if (records.length === 0) return { deleted: [] }

  const goals = await deps.listGoals()
  const byId = new Map(goals.map((g) => [g.id, g]))

  const deleted: string[] = []
  for (const record of records) {
    const goal = byId.get(record.id)
    if (!goal) continue // not active (user-deleted / evicted) — leave the record.

    const zeroProgress = goal.currentValue <= 0
    if (!zeroProgress) continue
    const lastChange = goal.updatedAt ?? record.createdAt
    if (deps.now - lastChange < STALE_THRESHOLD_MS) continue

    try {
      await deps.deleteGoal(record.id)
      deleted.push(record.id)
    } catch (e) {
      // Keep the id so cleanup retries next run; never let one failure abort the rest.
      console.warn('[goals] stale delete failed:', e instanceof Error ? e.name : 'Error')
    }
  }

  // Prune ONLY the ids we deleted. (Not "no longer active" ids — listGoals fails
  // open to [], and pruning on an empty list would wipe attribution for real
  // auto-goals. The 256 cap on write bounds any dead-id growth instead.)
  if (deleted.length > 0) {
    const deletedSet = new Set(deleted)
    deps.setAttribution(records.filter((r) => !deletedSet.has(r.id)))
  }
  return { deleted }
}

// --- Real side-effects -------------------------------------------------------

async function withTimeout<T>(
  ms: number,
  fn: (signal: AbortSignal) => Promise<T>,
  external?: AbortSignal
): Promise<T> {
  const ctrl = new AbortController()
  const onExternalAbort = (): void => ctrl.abort()
  const timer = setTimeout(() => ctrl.abort(), ms)
  if (external?.aborted) ctrl.abort()
  else external?.addEventListener('abort', onExternalAbort, { once: true })
  try {
    return await fn(ctrl.signal)
  } finally {
    clearTimeout(timer)
    external?.removeEventListener('abort', onExternalAbort)
  }
}

function parseUpdatedAt(value: unknown): number | null {
  if (typeof value !== 'string' || !value) return null
  const t = new Date(value).getTime()
  return Number.isNaN(t) ? null : t
}

/** Real listGoals: GET /v1/goals/all → active goals. Fails open to []. */
async function listActiveGoals(session: BackendSession): Promise<StaleGoal[]> {
  const external = getAbortSignal()
  try {
    return await withTimeout(
      REQUEST_TIMEOUT_MS,
      async (signal) => {
        const res = await net.fetch(`${session.apiBase}/v1/goals/all`, {
          method: 'GET',
          headers: { Authorization: `Bearer ${session.token}` },
          signal
        })
        if (!res.ok) {
          console.warn(`[goals] cleanup list HTTP ${res.status}`)
          return []
        }
        const data = await res.json()
        const list = Array.isArray(data)
          ? data
          : (((data as { goals?: unknown }).goals as unknown[]) ?? [])
        return (list as { id?: string; current_value?: number; updated_at?: string }[])
          .filter((g) => typeof g.id === 'string' && g.id.length > 0)
          .map((g) => ({
            id: g.id as string,
            currentValue: typeof g.current_value === 'number' ? g.current_value : 0,
            updatedAt: parseUpdatedAt(g.updated_at)
          }))
      },
      external
    )
  } catch (e) {
    console.warn('[goals] cleanup list failed:', e instanceof Error ? e.name : 'Error')
    return []
  }
}

/** Real deleteGoal: DELETE /v1/goals/{id}. Throws on non-OK so the id is kept. */
async function deleteGoalOnBackend(session: BackendSession, id: string): Promise<void> {
  const external = getAbortSignal()
  await withTimeout(
    REQUEST_TIMEOUT_MS,
    async (signal) => {
      const res = await net.fetch(`${session.apiBase}/v1/goals/${encodeURIComponent(id)}`, {
        method: 'DELETE',
        headers: { Authorization: `Bearer ${session.token}` },
        signal
      })
      // 404 = already gone; treat as success so we prune the dead id.
      if (!res.ok && res.status !== 404) throw new Error(`delete goal HTTP ${res.status}`)
    },
    external
  )
}

/** Production cleanup: bind real backend + appSettings side-effects and run. A
 *  no-op (nothing deleted) when there is no session. */
export async function removeStaleGoals(): Promise<StaleCleanupResult> {
  const session = getBackendSession()
  if (!session) return { deleted: [] }
  return removeStaleGoalsWith({
    listGoals: () => listActiveGoals(session),
    deleteGoal: (id) => deleteGoalOnBackend(session, id),
    getAttribution: () => getAppSettings().goalAutoGeneratedIds,
    setAttribution: (records) => {
      setAppSettings({ goalAutoGeneratedIds: records })
    },
    now: Date.now()
  })
}
